import React, { useEffect, useState } from 'react';
import { Lightbulb } from 'lucide-react';
import api from '../services/api';
import { Recommendation } from '../types';

export const Recommendations: React.FC = () => {
  const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchRecommendations();
  }, []);

  const fetchRecommendations = async () => {
    try {
      const response = await api.get('/recommendation/all', { timeout: 5000 });
      setRecommendations(response.data);
    } catch (error: any) {
      // Use mock data if backend not running
      if (error.code === 'ECONNABORTED' || error.message?.includes('Network')) {
        const mockRecs: Recommendation[] = [
          {
            title: "Switch to Public Transportation",
            description: "Reduce your carbon footprint by using public transportation instead of driving.",
            potential_savings: 2.5,
            impact: "High",
            priority: 1
          },
          {
            title: "Adopt Plant-Based Meals",
            description: "Replace some meat consumption with plant-based alternatives to reduce dietary emissions.",
            potential_savings: 1.8,
            impact: "Medium",
            priority: 2
          },
          {
            title: "Energy Efficiency at Home",
            description: "Use LED bulbs and optimize heating/cooling to reduce household energy consumption.",
            potential_savings: 1.2,
            impact: "Medium",
            priority: 3
          },
          {
            title: "Buy Sustainable Products",
            description: "Choose eco-friendly and sustainably produced items to lower embedded carbon emissions.",
            potential_savings: 0.8,
            impact: "Medium",
            priority: 4
          },
          {
            title: "Reduce Shopping Frequency",
            description: "Buy less new clothing and electronics, or choose secondhand options.",
            potential_savings: 1.5,
            impact: "Medium",
            priority: 5
          }
        ];
        setRecommendations(mockRecs);
      } else {
        console.error('Error fetching recommendations:', error);
      }
    } finally {
      setLoading(false);
    }
  };

  if (loading) return <div>Loading recommendations...</div>;

  const getImpactColor = (impact: string) => {
    switch (impact.toLowerCase()) {
      case 'high':
        return 'bg-red-100 text-red-800';
      case 'medium':
        return 'bg-yellow-100 text-yellow-800';
      case 'low':
        return 'bg-green-100 text-green-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  return (
    <div className="w-full max-w-4xl mx-auto p-8 bg-white rounded-lg shadow-lg">
      <div className="flex items-center gap-3 mb-8">
        <Lightbulb className="w-8 h-8 text-yellow-500" />
        <h2 className="text-3xl font-bold text-gray-800">AI-Powered Recommendations</h2>
      </div>

      <div className="space-y-4">
        {recommendations.map((rec, index) => (
          <div key={index} className="border-l-4 border-blue-500 bg-blue-50 p-6 rounded-r-lg hover:shadow-md transition">
            <div className="flex justify-between items-start mb-2">
              <h3 className="text-lg font-bold text-gray-800">{rec.title}</h3>
              <span className={`px-3 py-1 rounded-full text-sm font-semibold ${getImpactColor(rec.impact)}`}>
                {rec.impact} Impact
              </span>
            </div>
            <p className="text-gray-700 mb-4">{rec.description}</p>
            <div className="flex justify-between items-center">
              <div>
                <p className="text-sm text-gray-600">Potential Savings</p>
                <p className="text-xl font-bold text-green-600">{rec.potential_savings} kg CO2e</p>
              </div>
              <div className="text-right">
                <p className="text-sm text-gray-600">Priority</p>
                <p className="text-xl font-bold text-blue-600">#{rec.priority}</p>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};
